import Box from '@mui/material/Box';
import Container from '@mui/material/Container';

import ImageList from '@mui/material/ImageList';
import ImageListItem from '@mui/material/ImageListItem';

// import * as Images from '../../assets/collections/daylight/*';

import Image from "../../assets/collections/daylight/Daylight-1.jpg";

function Daylight () {
	const cache = {};

	function importAll(r) {
		r.keys().forEach((key) => (cache[key] = r(key)));
	};

	importAll(require.context('../../assets/collections/daylight', false, /\.jpg/));
	const images = Object.entries(cache).map(module => module[1]);

	React.useEffect(() => {
		console.log(images);
	},[])

	return (
		<>
			<Box height={'100vh'} width={'50wh'} sx={{ backgroundColour: 'red' }}>
				<ImageList sx={{ width: '100wh', height: '100vh', backgroundColor: 'blue', margin: 'auto 10%' }} cols={1} rowHeight={'auto'}>
					{images.map((item) => (
						<ImageListItem key={item}>
							<img src={`${item}?w=400&h=400&fit=crop&auto=format`}/>
						</ImageListItem>
					))}
				</ImageList>
			</Box>
			{/* <Box height={'100vh'} width={'100wh'} sx={{  }}>
				{ images.map(image => (
						// <img style={{ height: '300px', width: '200px' }} src={image}/>

						<Box
							component='img'
							sx={{
								height: '300px',
								width: '200px',
							}}
							src={image}
						>
						</Box>

					))
				}
			</Box> */}
		</>
	)
}

export default Daylight;
